import { encode } from 'base64url';

const clientId = 'your_client_id'; // replace with your Client ID
const redirectUri = 'https://yourredirecturi.com/callback'; // replace with your Redirect URI
const authorizationEndpoint = 'https://authorization_server_domain/auth'; 
// replace with the Authorization Server's domain

function handleResponse(response) {
    if (response.ok) {
        return response.json();
    } else {
        throw new Error('Error: ' + response.statusText);
    }
}

export function authorize() {
    const state = Math.random().toString(36).substring(2, 15);
    localStorage.setItem("stateKey", state);
    
    const scope = "read"; // specify the scopes your app needs
    const authUrl = `${authorizationEndpoint}?client_id=${encode(clientId)}&redirect_uri=${encode(redirectUri)}&response_type=code&scope=${encode(scope)}&state=${encode(state)}&show_dialog=true`;
    
    window.location = authUrl; // Redirect to Authorization server
}

export async function getToken(authCode) {
  const url = `https://authorization_server_domain/token?grant_type=authorization_code&client_id=${encode(clientId)}&redirect_uri=${encode(redirectUri)}&code=${encode(authCode)}`;
  
  let response = await fetch(url, { method: 'POST', headers: { "Content-Type": "application/x-www-form-urlencoded" } });
    response = handleResponse(response);
    return response.then((token) => {
      localStorage.setItem('access_token', token.access_token); // Store the access token in local storage
      return token;
    });
}